// stores/mahnwesen.svelte.js
// Status- und Logikverwaltung für das Mahnwesen (Svelte 5 Runes)

import { apiFetch } from '../apiFetch.js';
import { useMahnwesenPdf } from './mahnwesenPdf.svelte.js';
import { useMahnwesenMail } from './mahnwesenMail.svelte.js';

/**
 * Creates the central Mahnwesen store.
 */
export function createMahnwesenStore() {
	let data = $state(/** @type {{ klassen: any[] } | null} */ (null));
	let loading = $state(true);
	let error = $state(/** @type {string|null} */ (null));

	// Ferien-Logik
	let ferienAktiv = $state(false);
	let ferienBezeichnung = $state('');
	let heuteRetourniert = $state(0);

	// Filter und Auswahl
	let expandedKlassen = $state(/** @type {Set<string>} */ (new Set()));
	let mahnMode = $state('datum'); // "datum" oder "jahrgang"
	let selectedKlasse = $state('');

	// MD3 Filter & Bulk Actions
	let activeFilter = $state('Alle'); // "Alle", "1. Erinnerung", "Mahnung", "Lehrerkollegium"
	let selectedIds = $state(/** @type {Set<string>} */ (new Set()));

	const pdfStore = useMahnwesenPdf();
	const mailStore = useMahnwesenMail();

	// Abgeleitete Werte
	let klassen = $derived(data?.klassen ?? []);
	let totalOverdue = $derived(
		klassen.reduce(
			(/** @type {number} */ sum, /** @type {any} */ k) =>
				sum +
				k.schueler.reduce(
					(/** @type {number} */ s2, /** @type {any} */ sch) => s2 + sch.medien.length,
					0
				),
			0
		)
	);

	// Flache Liste für MD3 Table
	let flatSchueler = $derived(() => {
		let list = [];
		for (const k of klassen) {
			for (const s of k.schueler) {
				let maxTage = 0;
				for (const m of s.medien) {
					if (m.tage_ueberfaellig > maxTage) maxTage = m.tage_ueberfaellig;
				}

				let mahnstufe = 'Erledigt';
				if (s.klasse && s.klasse.toLowerCase() === 'lehrer') {
					mahnstufe = 'Lehrerkollegium';
				} else if (maxTage > 14) {
					mahnstufe = 'Mahnung';
				} else if (maxTage > 0) {
					mahnstufe = '1. Erinnerung';
				}

				list.push({ ...s, maxTage, mahnstufe, lehrer_email: k.lehrer_email });
			}
		}
		return list;
	});

	let filteredSchueler = $derived(() => {
		const list = flatSchueler();
		if (activeFilter === 'Alle') return list;
		return list.filter((/** @type {any} */ s) => s.mahnstufe === activeFilter);
	});

	/**
	 * Fetches Mahnwesen data from API.
	 */
	async function fetchData() {
		loading = true;
		error = null;
		try {
			const endpoint =
				mahnMode === 'datum' ? '/api/mahnwesen' : '/api/mahnwesen/ueberfaellig_jahrgang';
			const res = await apiFetch(endpoint);
			if (!res.ok) throw new Error((await res.text()) || 'Fehler beim Laden');
			const json = await res.json();
			data = json;
			ferienAktiv = json.ferien_aktiv || false;
			ferienBezeichnung = json.ferien_bezeichnung || '';
			heuteRetourniert = json.heute_retourniert || 0;
			selectedIds.clear();
		} catch (e) {
			error = String(e);
		} finally {
			loading = false;
		}
	}

	/** @param {string} klasse */
	function toggleKlasse(klasse) {
		const s = new Set(expandedKlassen);
		if (s.has(klasse)) s.delete(klasse);
		else s.add(klasse);
		expandedKlassen = s;
	}

	/** @param {string} id */
	function toggleSelect(id) {
		const s = new Set(selectedIds);
		if (s.has(id)) s.delete(id);
		else s.add(id);
		selectedIds = s;
	}

	/** @param {boolean} selectAll */
	function toggleSelectAll(selectAll) {
		if (!selectAll) {
			selectedIds = new Set();
		} else {
			const currentList = filteredSchueler();
			selectedIds = new Set(currentList.map((/** @type {any} */ s) => s.schueler_id));
		}
	}

	/** Wrapper for bulk printing that supplies needed state context. */
	async function printSelectedMahnungenWrapper() {
		await pdfStore.printSelectedMahnungen(selectedIds, filteredSchueler, fetchData);
	}

	return {
		get data() {
			return data;
		},
		get loading() {
			return loading;
		},
		get error() {
			return error;
		},
		get expandedKlassen() {
			return expandedKlassen;
		},
		get mahnMode() {
			return mahnMode;
		},
		set mahnMode(v) {
			mahnMode = v;
		},
		get selectedKlasse() {
			return selectedKlasse;
		},
		set selectedKlasse(v) {
			selectedKlasse = v;
		},
		get klassen() {
			return klassen;
		},
		get totalOverdue() {
			return totalOverdue;
		},
		get ferienAktiv() {
			return ferienAktiv;
		},
		get ferienBezeichnung() {
			return ferienBezeichnung;
		},
		get heuteRetourniert() {
			return heuteRetourniert;
		},
		get activeFilter() {
			return activeFilter;
		},
		set activeFilter(v) {
			activeFilter = v;
			selectedIds.clear();
		},
		get selectedIds() {
			return selectedIds;
		},
		get filteredSchueler() {
			return filteredSchueler();
		},

		fetchData,
		toggleKlasse,
		toggleSelect,
		toggleSelectAll,

		// Expose mail store methods and state directly
		get modalOpen() {
			return mailStore.modalOpen;
		},
		get modalKlasse() {
			return mailStore.modalKlasse;
		},
		get modalEmail() {
			return mailStore.modalEmail;
		},
		set modalEmail(v) {
			mailStore.modalEmail = v;
		},
		get modalSending() {
			return mailStore.modalSending;
		},
		get modalMsg() {
			return mailStore.modalMsg;
		},
		openModal: mailStore.openModal,
		closeModal: mailStore.closeModal,
		sendMahnliste: mailStore.sendMahnliste,

		// Expose pdf store methods and state directly
		get pdfLoading() {
			return pdfStore.pdfLoading;
		},
		get elternPdfLoading() {
			return pdfStore.elternPdfLoading;
		},
		get klassePdfLoading() {
			return pdfStore.klassePdfLoading;
		},
		get globalErrorToast() {
			return pdfStore.globalErrorToast;
		},
		printSelectedMahnungen: printSelectedMahnungenWrapper,
		downloadPDF: pdfStore.downloadPDF,
		downloadElternPDF: pdfStore.downloadElternPDF,
		downloadKlassePDF: pdfStore.downloadKlassePDF
	};
}

export const mahnwesenStore = createMahnwesenStore();

import { apiFetch } from '../apiFetch.js';

/**
 * Handles PDF generation logic for Mahnwesen.
 */
export function useMahnwesenPdf() {
	let pdfLoading = $state(false);
	let elternPdfLoading = $state(false);
	let klassePdfLoading = $state(false);
	let globalErrorToast = $state(/** @type {string|null} */ (null));

	/**
	 * Prints selected Mahnungen by collecting ausleih_ids.
	 * @param {Set<string>} selectedIds
	 * @param {Function} getFilteredSchueler
	 * @param {Function} refreshData
	 */
	async function printSelectedMahnungen(selectedIds, getFilteredSchueler, refreshData) {
		if (selectedIds.size === 0) return;

		pdfLoading = true;
		try {
			const currentList = getFilteredSchueler();
			const ausleihIds = [];
			for (const schuelerId of selectedIds) {
				const s = currentList.find(/** @type {any} */ (x) => x.schueler_id === schuelerId);
				if (s && s.medien) {
					for (const m of s.medien) {
						if (m.ausleihe_id) ausleihIds.push(m.ausleihe_id);
					}
				}
			}

			if (ausleihIds.length === 0) {
				alert('Keine überfälligen Medien für die ausgewählten Schüler gefunden.');
				return;
			}

			const res = await apiFetch('/api/admin/mahnungen/bulk-print', {
				method: 'POST',
				body: JSON.stringify({ ausleih_ids: ausleihIds })
			});

			if (!res.ok)
				throw new Error(
					'Bulk-PDF-Erzeugung fehlgeschlagen: ' + ((await res.text()) || res.statusText)
				);

			const blob = await res.blob();
			const url = URL.createObjectURL(blob);
			const a = document.createElement('a');
			a.href = url;
			a.download = `Mahnliste_Bulk_${new Date().toISOString().slice(0, 10)}.pdf`;
			a.click();
			URL.revokeObjectURL(url);

			selectedIds.clear();
			await refreshData();
		} catch (e) {
			alert('Fehler: ' + String(e));
		} finally {
			pdfLoading = false;
		}
	}

	/**
	 * Downloads the global Mahnliste PDF.
	 */
	async function downloadPDF() {
		pdfLoading = true;
		try {
			const res = await apiFetch('/api/mahnwesen/pdf');
			if (!res.ok) throw new Error('PDF-Erzeugung fehlgeschlagen');
			const blob = await res.blob();
			const url = URL.createObjectURL(blob);
			const a = document.createElement('a');
			a.href = url;
			a.download = `mahnliste_${new Date().toISOString().slice(0, 10)}.pdf`;
			a.click();
			URL.revokeObjectURL(url);
		} catch (e) {
			alert('Fehler: ' + String(e));
		} finally {
			pdfLoading = false;
		}
	}

	/**
	 * Downloads the Eltern Mahnbriefe PDF.
	 */
	async function downloadElternPDF() {
		elternPdfLoading = true;
		globalErrorToast = null;
		try {
			const res = await apiFetch('/api/reports/overdue-pdf');
			if (!res.ok) throw new Error((await res.text()) || 'PDF-Erzeugung fehlgeschlagen');
			const blob = await res.blob();
			const url = URL.createObjectURL(blob);
			const a = document.createElement('a');
			a.href = url;
			a.download = `mahnbriefe_${new Date().toISOString().slice(0, 10)}.pdf`;
			a.click();
			URL.revokeObjectURL(url);
		} catch (e) {
			globalErrorToast = 'Fehler: ' + String(e);
			setTimeout(() => (globalErrorToast = null), 4000);
		} finally {
			elternPdfLoading = false;
		}
	}

	/**
	 * Downloads the PDF for a specific class.
	 * @param {string} selectedKlasse
	 */
	async function downloadKlassePDF(selectedKlasse) {
		if (!selectedKlasse) return;
		klassePdfLoading = true;
		globalErrorToast = null;
		try {
			const res = await apiFetch(`/api/print/mahnung/klasse/${selectedKlasse}`);
			if (!res.ok) {
				const errText = await res.text();
				throw new Error(errText || 'Keine überfälligen Ausleihen gefunden');
			}
			const blob = await res.blob();
			const url = URL.createObjectURL(blob);
			const a = document.createElement('a');
			a.href = url;
			a.download = `Mahnliste_Klasse_${selectedKlasse}.pdf`;
			a.click();
			URL.revokeObjectURL(url);
		} catch (e) {
			globalErrorToast = String(e);
			setTimeout(() => (globalErrorToast = null), 4000);
		} finally {
			klassePdfLoading = false;
		}
	}

	return {
		get pdfLoading() {
			return pdfLoading;
		},
		get elternPdfLoading() {
			return elternPdfLoading;
		},
		get klassePdfLoading() {
			return klassePdfLoading;
		},
		get globalErrorToast() {
			return globalErrorToast;
		},
		set globalErrorToast(v) {
			globalErrorToast = v;
		},
		printSelectedMahnungen,
		downloadPDF,
		downloadElternPDF,
		downloadKlassePDF
	};
}

export const toastStore = new (class {
	/** @type {{id: number, message: string, type: 'success' | 'error' | 'info'}[]} */
	toasts = $state([]);

	#counter = 0;
	/** @type {Map<number, ReturnType<typeof setTimeout>>} */
	#timers = new Map();

	/**
	 * @param {string} message
	 * @param {'success' | 'error' | 'info'} [type='info']
	 */
	addToast(message, type = 'info') {
		const id = this.#counter++;
		this.toasts.push({ id, message, type });
		this.#timers.set(
			id,
			setTimeout(() => this.removeToast(id), 5000)
		);
	}

	/**
	 * @param {number} id
	 */
	removeToast(id) {
		const timer = this.#timers.get(id);
		if (timer !== undefined) {
			clearTimeout(timer);
			this.#timers.delete(id);
		}
		this.toasts = this.toasts.filter((t) => t.id !== id);
	}
})();
